/// An abstract `Expr` node. Wraps `Node` for type clarity.
#[derive(Debug, Clone, Copy)]
pub struct Expr<'a>(pub Node<'a>);

impl<'a> std::ops::Deref for Expr<'a> {
    type Target = Node<'a>;
    fn deref(&self) -> &Node<'a> { &self.0 }
}

impl<'a> FromArena<'a> for Expr<'a> {
    fn from_arena(reader: NodeReader<'a>, id: NodeId) -> Option<Self> {
        Node::resolve(reader, id).map(Expr)
    }
}

/// An abstract `Stmt` node. Wraps `Node` for type clarity.
#[derive(Debug, Clone, Copy)]
pub struct Stmt<'a>(pub Node<'a>);

impl<'a> std::ops::Deref for Stmt<'a> {
    type Target = Node<'a>;
    fn deref(&self) -> &Node<'a> { &self.0 }
}

impl<'a> FromArena<'a> for Stmt<'a> {
    fn from_arena(reader: NodeReader<'a>, id: NodeId) -> Option<Self> {
        Node::resolve(reader, id).map(Stmt)
    }
}

#[derive(Clone, Copy)]
pub struct AggregateFunctionCall<'a> {
    raw: &'a crate::ffi::AggregateFunctionCall,
    reader: NodeReader<'a>,
}

impl std::fmt::Debug for AggregateFunctionCall<'_> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        self.raw.fmt(f)
    }
}

impl<'a> AggregateFunctionCall<'a> {
    pub fn func_name(&self) -> &'a str {
        self.raw.func_name.as_str(self.reader.source())
    }
    pub fn flags(&self) -> AggregateFunctionCallFlags {
        self.raw.flags
    }
    pub fn args(&self) -> Option<ExprList<'a>> {
        FromArena::from_arena(self.reader, self.raw.args)
    }
    pub fn orderby(&self) -> Option<OrderByList<'a>> {
        FromArena::from_arena(self.reader, self.raw.orderby)
    }
    pub fn filter_clause(&self) -> Option<Expr<'a>> {
        FromArena::from_arena(self.reader, self.raw.filter_clause)
    }
    pub fn over_clause(&self) -> Option<WindowDef<'a>> {
        FromArena::from_arena(self.reader, self.raw.over_clause)
    }
}

impl<'a> FromArena<'a> for AggregateFunctionCall<'a> {
    fn from_arena(reader: NodeReader<'a>, id: NodeId) -> Option<Self> {
        let (ptr, _) = reader.node_ptr(id)?;
        Some(AggregateFunctionCall { raw: unsafe { &*(ptr as *const crate::ffi::AggregateFunctionCall) }, reader })
    }
}

